     1→import type { Metadata } from "next";
     2→import localFont from "next/font/local";
     3→import Navbar from "@/components/Navbar";
     4→import Footer from "@/components/Footer";
     5→import Analytics from "@/components/Analytics";
     6→import BrowserDetectionBanner from "@/components/BrowserDetectionBanner";
     7→import { siteConfig } from "../../site.config";
     8→import { ThemeProvider } from "@/components/ThemeProvider";
     9→import { LanguageProvider } from "@/components/LanguageProvider";
    10→import { getAllSeries, getAllBooks, getSeriesData } from "@/lib/markdown";
    11→import { resolveLocale } from "@/lib/i18n";
    12→import "./globals.css";
    13→import "katex/dist/katex.min.css";
    14→
    15→const inter = localFont({
    16→  src: [
    17→    {
    18→      path: "../fonts/Inter-Regular.woff2",
    19→      weight: "400",
    20→      style: "normal",
    21→    },
    22→    {
    23→      path: "../fonts/Inter-Bold.woff2",
    24→      weight: "700",
    25→      style: "normal",
    26→    },
    27→  ],
    28→  variable: "--font-inter",
    29→});
    30→
    31→const baskerville = localFont({
    32→  src: [
    33→    {
    34→      path: "../fonts/LibreBaskerville-Regular.ttf",
    35→      weight: "400",
    36→      style: "normal",
    37→    },
    38→    {
    39→      path: "../fonts/LibreBaskerville-Bold.ttf",
    40→      weight: "700",
    41→      style: "normal",
    42→    },
    43→    {
    44→      path: "../fonts/LibreBaskerville-Italic.ttf",
    45→      weight: "400",
    46→      style: "italic",
    47→    },
    48→  ],
    49→  variable: "--font-baskerville",
    50→});
    51→
    52→const siteTwitterHandle = (() => {
    53→  const url = siteConfig.social?.twitter ?? '';
    54→  const m = url.match(/(?:twitter\.com|x\.com)\/([^/?#]+)/);
    55→  return m ? `@${m[1]}` : undefined;
    56→})();
    57→
    58→// Build icon metadata with explicit MIME type so browsers correctly handle
    59→// all formats. Without this, .ico files served via the metadata API lack
    60→// type="image/x-icon" and may be ignored in favour of app/favicon.ico.
    61→const faviconSrc = siteConfig.logo?.favicon || "/icon.svg";
    62→const ext = faviconSrc.split('.').pop()?.toLowerCase();
    63→const faviconMeta =
    64→  ext === 'ico' ? [{ url: faviconSrc, type: 'image/x-icon', sizes: 'any' }] :
    65→  ext === 'png' ? [{ url: faviconSrc, type: 'image/png' }] :
    66→  ext === 'svg' ? [{ url: faviconSrc, type: 'image/svg+xml' }] :
    67→  faviconSrc;
    68→
    69→const feedAlternates = (() => {
    70→  const { format } = siteConfig.feed;
    71→  const types: Record<string, string> = {};
    72→  if (format === 'rss' || format === 'both') types['application/rss+xml'] = '/feed.xml';
    73→  if (format === 'atom' || format === 'both') types['application/atom+xml'] = '/feed.atom';
    74→  return Object.keys(types).length > 0 ? { types } : undefined;
    75→})();
    76→
    77→export const metadata: Metadata = {
    78→  metadataBase: new URL(siteConfig.baseUrl),
    79→  title: resolveLocale(siteConfig.title),
    80→  description: resolveLocale(siteConfig.description),
    81→  icons: {
    82→    icon: faviconMeta,
    83→  },
    84→  ...(feedAlternates && { alternates: feedAlternates }),
    85→  openGraph: {
    86→    siteName: resolveLocale(siteConfig.title),
    87→    locale: siteConfig.i18n.defaultLocale,
    88→    type: 'website',
    89→    images: [{ url: siteConfig.ogImage, width: 1200, height: 630 }],
    90→  },
    91→  twitter: {
    92→    card: 'summary',
    93→    site: siteTwitterHandle,
    94→    creator: siteTwitterHandle,
    95→  },
    96→};
    97→
    98→export default function RootLayout({
    99→  children,
   100→}: Readonly<{
   101→  children: React.ReactNode;
   102→}>) {
   103→  const features = siteConfig.features;
   104→
   105→  // Build series list for navbar (only when series feature is enabled)
   106→  const seriesNavItem = siteConfig.nav.find(item => item.url === '/series');
   107→  const featuredSeries = seriesNavItem?.dropdown;
   108→  let seriesList: { name: string; slug: string }[] = [];
   109→  if (features?.series?.enabled !== false) {
   110→    const allSeries = getAllSeries();
   111→    const seriesKeys = Object.keys(allSeries).sort();
   112→    const filteredKeys = featuredSeries && featuredSeries.length > 0
   113→      ? seriesKeys.filter(slug => featuredSeries.includes(slug))
   114→      : [];
   115→    seriesList = filteredKeys.map(slug => ({
   116→      name: getSeriesData(slug)?.title || allSeries[slug][0]?.series || slug,
   117→      slug,
   118→    }));
   119→  }
   120→
   121→  // Build books list for navbar (only when books feature is enabled)
   122→  const booksNavItem = siteConfig.nav.find(item => item.url === '/books');
   123→  const featuredBookSlugs = booksNavItem?.dropdown;
   124→  let booksList: { name: string; slug: string }[] = [];
   125→  if (features?.books?.enabled !== false) {
   126→    const allBooks = getAllBooks();
   127→    booksList = featuredBookSlugs && featuredBookSlugs.length > 0
   128→      ? allBooks
   129→          .filter(book => featuredBookSlugs.includes(book.slug))
   130→          .map(book => ({ name: book.title, slug: book.slug }))
   131→      : [];
   132→  }
   133→
   134→  return (
   135→    <html lang={siteConfig.i18n.defaultLocale} suppressHydrationWarning>
   136→      <body
   137→        className={`${inter.variable} ${baskerville.variable} font-sans min-h-screen transition-colors duration-300`}
   138→        data-palette={siteConfig.themeColor}
   139→        suppressHydrationWarning
   140→      >
   141→        {/* Skip to main content link for accessibility */}
   142→        <a
   143→          href="#main-content"
   144→          className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 focus:z-[100] focus:px-4 focus:py-2 focus:bg-accent focus:text-white focus:rounded-lg focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2"
   145→        >
   146→          Skip to main content
   147→        </a>
   148→        <ThemeProvider>
