   211→  }
   212→
   213→  return (
   214→    <div>
   215→      {has('hero') && (
   216→        <Hero
   217→          tagline={siteConfig.hero.tagline}
   218→          title={siteConfig.hero.title}
   219→          subtitle={siteConfig.hero.subtitle}
   220→          postCount={heroPostCount}
   221→          seriesCount={heroSeriesCount}
   222→          bookCount={heroBookCount}
   223→          flowCount={heroFlowCount}
