   226→            posts:  features?.posts?.name,
   227→            series: features?.series?.name,
   228→            books:  features?.books?.name,
   229→          }}
   230→        />
   231→      )}
   232→
   233→      <div className="layout-main pt-0 md:pt-0 [&>*:last-child]:mb-0">
   234→        {renderList}
   235→      </div>
   236→    </div>
   237→  );
   238→}
