    28→/**
    29→ * Generates the static paths for all blog posts at build time.
    30→ * This ensures fast page loads and SEO optimization.
    31→ */
    32→export async function generateStaticParams() {
    33→  if (getPostsBasePath() !== 'posts') return [{ slug: '_' }]; // Route disabled; custom path handles this
    34→  const posts = getAllPosts();
    35→  if (posts.length === 0) return [{ slug: '_' }];
    36→  // Work around Next dev static-param checks for percent-encoded Unicode paths
    37→  // under `output: "export"` by including encoded variants only in development.
    38→  // Production export keeps raw segment values.
    39→  const slugs = new Set<string>();
    40→  for (const post of posts) {
    41→    slugs.add(post.slug);
    42→    if (process.env.NODE_ENV !== 'production') {
    43→      slugs.add(encodeURIComponent(post.slug));
    44→    }
    45→  }
    46→  return Array.from(slugs).map((slug) => ({ slug }));
    47→}
    48→
    49→export const dynamicParams = false;
    50→
    51→export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
    52→  const { slug: rawSlug } = await params;
    53→  const post = resolvePostFromParam(rawSlug);
    54→
    55→  if (!post) {
    56→    return {
    57→      title: 'Post Not Found',
    58→    };
    59→  }
    60→
    61→  const ogImage = post.coverImage && !post.coverImage.startsWith('text:') && !post.coverImage.startsWith('./')
    62→    ? post.coverImage
    63→    : siteConfig.ogImage;
    64→
    65→  return {
    66→    title: `${post.title} | ${resolveLocale(siteConfig.title)}`,
    67→    description: post.excerpt,
    68→    openGraph: {
    69→      title: post.title,
    70→      description: post.excerpt,
    71→      type: 'article',
    72→      publishedTime: post.date,
    73→      authors: post.authors,
    74→      images: [
    75→        {
    76→          url: ogImage,
    77→          width: 1200,
    78→          height: 630,
    79→          alt: post.title,
    80→        },
    81→      ],
    82→      siteName: resolveLocale(siteConfig.title),
    83→    },
    84→    twitter: {
    85→      card: 'summary_large_image',
    86→      title: post.title,
    87→      description: post.excerpt,
    88→      images: [ogImage],
    89→    },
    90→  };
    91→}
