   123→    seriesTitle = seriesData?.title;
   124→  }
   125→
   126→  // Default to standard post layout
   127→  return <PostLayout post={post} relatedPosts={relatedPosts} seriesPosts={seriesPosts} seriesTitle={seriesTitle} prevPost={prev} nextPost={next} backlinks={backlinks} slugRegistry={slugRegistry} />;
