     8→export async function generateStaticParams() {
     9→  const books = getAllBooks();
    10→  if (books.length === 0) return [{ slug: '_', chapter: '_' }];
    11→  const params: { slug: string; chapter: string }[] = [];
    12→
    13→  for (const book of books) {
    14→    for (const ch of book.chapters) {
    15→      // Only include chapters whose files exist and parse successfully.
    16→      // A chapter listed in index.mdx but not yet written (or with invalid
    17→      // frontmatter) would cause notFound() at render time, which in
    18→      // output:export dev mode surfaces as a confusing "missing param" 500.
    19→      if (getBookChapter(book.slug, ch.id) !== null) {
    20→        params.push({ slug: book.slug, chapter: ch.id });
    21→      }
    22→    }
    23→  }
    24→
    25→  // Ensure we never return an empty array with output: export
    26→  return params.length > 0 ? params : [{ slug: '_', chapter: '_' }];
    27→}
