    31→export async function generateMetadata({ params }: { params: Promise<{ slug: string; chapter: string }> }): Promise<Metadata> {
    32→  const { slug: rawSlug, chapter: rawChapter } = await params;
    33→  const slug = decodeURIComponent(rawSlug);
    34→  const chapterSlug = decodeURIComponent(rawChapter);
    35→
    36→  const book = getBookData(slug);
    37→  const chapter = getBookChapter(slug, chapterSlug);
    38→
    39→  if (!book || !chapter) {
    40→    return { title: 'Chapter Not Found' };
    41→  }
    42→
    43→  return {
    44→    title: `${chapter.title} - ${book.title} | ${resolveLocale(siteConfig.title)}`,
    45→    description: chapter.excerpt,
    46→  };
    47→}
