    28→export async function generateStaticParams() {
    29→  const params: { slug: string; postSlug: string }[] = [];
    30→
    31→  // Custom posts basePath — all posts served at /[basePath]/[slug]
    32→  const basePath = getPostsBasePath();
    33→  if (basePath !== 'posts') {
    34→    getAllPosts().forEach(post => { params.push({ slug: basePath, postSlug: post.slug }); });
    35→  }
    36→
    37→  // Series custom paths — only posts belonging to that series
    38→  for (const [seriesSlug, customPath] of Object.entries(getSeriesCustomPaths())) {
    39→    getSeriesPosts(seriesSlug).forEach(post => { params.push({ slug: customPath, postSlug: post.slug }); });
    40→  }
    41→
    42→  // Placeholder keeps Next.js happy with output: export when no custom paths configured.
    43→  // dynamicParams = false ensures any unrecognised slug/postSlug combo returns 404.
    44→  return params.length > 0 ? params : [{ slug: '_', postSlug: '_' }];
    45→}
