    94→export default async function PrefixPostPage({
    95→  params,
    96→}: {
    97→  params: Promise<{ slug: string; postSlug: string }>;
    98→}) {
    99→  const { slug: prefix, postSlug: rawPostSlug } = await params;
   100→
   101→  // Validate the prefix is a known custom path
   102→  const basePath = getPostsBasePath();
   103→  const customPaths = getSeriesCustomPaths();
   104→  const isValidBasePath = prefix === basePath && basePath !== 'posts';
   105→  const matchedSeriesSlug = Object.entries(customPaths).find(([, path]) => path === prefix)?.[0];
   106→
   107→  if (!isValidBasePath && !matchedSeriesSlug) {
   108→    notFound();
   109→  }
   110→
   111→  const post = resolvePostFromParam(rawPostSlug);
   112→  if (!post) {
   113→    notFound();
   114→  }
   115→
   116→  const layout = post.layout || 'post';
   117→
   118→  if (layout === 'simple') {
   119→    return <SimpleLayout post={post} />;
   120→  }
   121→
   122→  const relatedPosts = getRelatedPosts(post.slug);
   123→  const { prev, next } = getAdjacentPosts(post.slug);
   124→  const slugRegistry = buildSlugRegistry();
   125→  const backlinks = getBacklinks(post.slug);
   126→  let seriesPosts: PostData[] = [];
   127→  let seriesTitle: string | undefined;
   128→
   129→  if (post.series) {
   130→    seriesPosts = getSeriesPosts(post.series);
   131→    const seriesData = getSeriesData(post.series);
   132→    seriesTitle = seriesData?.title;
   133→  }
   134→
   135→  return (
   136→    <PostLayout
   137→      post={post}
   138→      relatedPosts={relatedPosts}
   139→      seriesPosts={seriesPosts}
   140→      seriesTitle={seriesTitle}
   141→      prevPost={prev}
   142→      nextPost={next}
   143→      backlinks={backlinks}
   144→      slugRegistry={slugRegistry}
   145→    />
   146→  );
   147→}
