   233→export function getAllPosts(): PostData[] {
   234→  const allPostsData: PostData[] = [];
   235→
   236→  // Helper to process a directory
   237→  const processDirectory = (dir: string, isSeriesDir: boolean = false) => {
   238→    if (!fs.existsSync(dir)) return;
   239→    
   240→    const items = fs.readdirSync(dir, { withFileTypes: true });
   241→
   242→    items.forEach((item) => {
   243→      let fullPath = '';
   244→      let slug = '';
   245→      let dateFromFileName = undefined;
   246→
   247→      const dateRegex = /^(\d{4}-\d{2}-\d{2})-(.*)$/;
   248→      const rawName = item.name.replace(/\.mdx?$/, '');
   249→      const match = rawName.match(dateRegex);
   250→      
   251→      if (match) {
   252→        dateFromFileName = match[1];
   253→        if (siteConfig.posts?.includeDateInUrl) {
   254→          slug = rawName;
   255→        } else {
   256→          slug = match[2];
   257→        }
   258→      } else {
   259→        slug = rawName;
   260→      }
   261→
   262→      // Handle Series Directory logic
   263→      if (isSeriesDir) {
   264→        if (item.isDirectory()) {
   265→           const seriesSlug = item.name; // Folder name is series slug
   266→           const seriesPath = path.join(dir, item.name);
   267→           const seriesItems = fs.readdirSync(seriesPath, { withFileTypes: true });
   268→           
   269→           seriesItems.forEach(sItem => {
   270→             // Skip series metadata file itself
   271→             if (sItem.name === 'index.md' || sItem.name === 'index.mdx') return;
   272→
   273→             // 1. File-based posts: series/slug/post.mdx
   274→             if (sItem.isFile() && (sItem.name.endsWith('.md') || sItem.name.endsWith('.mdx'))) {
   275→               const sRawName = sItem.name.replace(/\.mdx?$/, '');
   276→               const sMatch = sRawName.match(dateRegex);
   277→               let sSlug = sRawName;
   278→               let sDate = undefined;
   279→               if (sMatch) {
   280→                 sDate = sMatch[1];
   281→                 sSlug = siteConfig.posts?.includeDateInUrl ? sRawName : sMatch[2];
   282→               }
   283→               
   284→               allPostsData.push(parseMarkdownFile(
   285→                 path.join(seriesPath, sItem.name), 
   286→                 sSlug, 
   287→                 sDate, 
   288→                 seriesSlug 
   289→               ));
   290→             } 
   291→             // 2. Folder-based posts: series/slug/post-folder/index.mdx
   292→             else if (sItem.isDirectory()) {
   293→                 const postFolder = path.join(seriesPath, sItem.name);
   294→                 const postIndexMdx = path.join(postFolder, 'index.mdx');
   295→                 const postIndexMd = path.join(postFolder, 'index.md');
   296→                 let postFullPath = '';
   297→                 
   298→                 if (fs.existsSync(postIndexMdx)) postFullPath = postIndexMdx;
   299→                 else if (fs.existsSync(postIndexMd)) postFullPath = postIndexMd;
   300→                 
   301→                 if (postFullPath) {
   302→                     // Handle date prefix in folder name
   303→                     const sMatch = sItem.name.match(dateRegex);
   304→                     let sSlug = sItem.name;
   305→                     let sDate = undefined;
   306→                     
   307→                     if (sMatch) {
   308→                       sDate = sMatch[1];
   309→                       sSlug = siteConfig.posts?.includeDateInUrl ? sItem.name : sMatch[2];
   310→                     }
   311→
   312→                     allPostsData.push(parseMarkdownFile(
   313→                       postFullPath, 
   314→                       sSlug, 
   315→                       sDate, 
   316→                       seriesSlug 
   317→                     ));
   318→                 }
   319→             }
   320→           });
   321→           return; // Processed this series folder
   322→        }
   323→      }
   324→
   325→      // Standard Posts logic (outside series)
   326→      if (item.isFile()) {
   327→        if (!item.name.endsWith('.mdx') && !item.name.endsWith('.md')) return;
   328→        fullPath = path.join(dir, item.name);
   329→        allPostsData.push(parseMarkdownFile(fullPath, slug, dateFromFileName));
   330→      } else if (item.isDirectory()) {
   331→        const indexPathMdx = path.join(dir, item.name, 'index.mdx');
   332→        const indexPathMd = path.join(dir, item.name, 'index.md');
   333→        if (fs.existsSync(indexPathMdx)) fullPath = indexPathMdx;
   334→        else if (fs.existsSync(indexPathMd)) fullPath = indexPathMd;
   335→        else return;
   336→        
   337→        allPostsData.push(parseMarkdownFile(fullPath, slug, dateFromFileName));
   338→      }
   339→    });
   340→  };
   341→
   342→  processDirectory(contentDirectory);
   343→  processDirectory(seriesDirectory, true);
   344→
   345→  return allPostsData
   346→    .filter(post => {
   347→      if (post.category === 'Page') return false;
   348→      
   349→      if (process.env.NODE_ENV === 'production' && post.draft) {
   350→        return false;
   351→      }
   352→
   353→      if (!siteConfig.posts?.showFuturePosts) {
   354→        const postDate = new Date(post.date);
   355→        const now = new Date();
   356→        if (postDate > now) return false;
   357→      }
   358→      return true;
   359→    })
   360→    .sort((a, b) => (a.date < b.date ? 1 : -1));
   361→}
