   374→function findPostFile(name: string, targetSlug: string): PostData | null {
   375→  // Check standard posts
   376→  let fullPath = path.join(contentDirectory, `${name}.mdx`);
   377→  if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   378→  
   379→  fullPath = path.join(contentDirectory, `${name}.md`);
   380→  if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   381→
   382→  if (fs.existsSync(path.join(contentDirectory, name))) {
   383→    fullPath = path.join(contentDirectory, name, 'index.mdx');
   384→    if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   385→    
   386→    fullPath = path.join(contentDirectory, name, 'index.md');
   387→    if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   388→  }
   389→
   390→  // Check series posts
   391→  if (fs.existsSync(seriesDirectory)) {
   392→    const seriesFolders = fs.readdirSync(seriesDirectory);
   393→    for (const folder of seriesFolders) {
   394→      const folderPath = path.join(seriesDirectory, folder);
   395→      if (!fs.statSync(folderPath).isDirectory()) continue;
   396→
   397→      // Check file-based
   398→      fullPath = path.join(folderPath, `${name}.mdx`);
   399→      if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   400→
   401→      fullPath = path.join(folderPath, `${name}.md`);
   402→      if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   403→
   404→      // Check folder-based
   405→      const postFolderPath = path.join(folderPath, name);
   406→      if (fs.existsSync(postFolderPath) && fs.statSync(postFolderPath).isDirectory()) {
   407→         fullPath = path.join(postFolderPath, 'index.mdx');
   408→         if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   409→         
   410→         fullPath = path.join(postFolderPath, 'index.md');
   411→         if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   412→      }
   413→    }
   414→  }
   415→
   416→  return null;
   417→}
