    80→export function calculateReadingTime(content: string): string {
    81→  const wordsPerMinute = 200;
    82→  const hanCharsPerMinute = 300;
    83→
    84→  // Strip tags and common markdown syntax before counting.
    85→  const text = content
    86→    .replace(/<\/?[^>]+(>|$)/g, "")
    87→    .replace(/```[\s\S]*?```/g, "")
    88→    .replace(/`[^`]*`/g, "")
    89→    .replace(/!\[[^\]]*\]\([^)]+\)/g, "")
    90→    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    91→    .replace(/[#*_~>\-[\]()]/g, " ");
    92→
    93→  const hanCharCount = (text.match(/[\u3400-\u4DBF\u4E00-\u9FFF\uF900-\uFAFF]/g) || []).length;
    94→  const latinWordCount = (text.match(/[A-Za-z0-9]+(?:['’-][A-Za-z0-9]+)*/g) || []).length;
    95→
    96→  const estimatedMinutes = (latinWordCount / wordsPerMinute) + (hanCharCount / hanCharsPerMinute);
    97→  const minutes = Math.max(1, Math.ceil(estimatedMinutes));
    98→  return `${minutes} min read`;
    99→}
