   101→export function generateExcerpt(content: string): string {
   102→  let plain = content.replace(/^#+\s+/gm, '');
   103→  plain = plain.replace(/```[\s\S]*?```/g, '');
   104→  plain = plain.replace(/!\[[^\]]*\]\([^)]+\)/g, '');
   105→  plain = plain.replace(/\*\[([^\]]+)\*\]\([^)]+\)/g, '$1');
   106→  plain = plain.replace(/(\$\*\*|__|\*|_)/g, '');
   107→  plain = plain.replace(/`([^`]+)`/g, '$1');
   108→  plain = plain.replace(/^>\s+/gm, '');
   109→  plain = plain.replace(/\s+/g, ' ').trim();
   110→  
   111→  if (plain.length <= 160) {
   112→    return plain;
   113→  }
   114→  return plain.slice(0, 160).trim() + '...';
   115→}
