   479→/**
   480→ * Load the content and frontmatter of a locale variant file, e.g. about.zh.mdx.
   481→ * Returns null when the file does not exist or cannot be parsed.
   482→ */
   483→function loadLocaleContent(slug: string, locale: string): { content: string; title?: string; excerpt?: string; headings?: Heading[] } | null {
   484→  for (const ext of ['.mdx', '.md']) {
   485→    const filePath = path.join(pagesDirectory, `${slug}.${locale}${ext}`);
   486→    if (fs.existsSync(filePath)) {
   487→      try {
   488→        const { data, content } = matter(fs.readFileSync(filePath, 'utf8'));
   489→        const body = content.replace(/^\s*#\s+[^\n]+/, '').trim();
   490→        return {
   491→          content: body,
   492→          title: typeof data.title === 'string' ? data.title : undefined,
   493→          excerpt: typeof data.excerpt === 'string' ? data.excerpt : undefined,
   494→          headings: getHeadings(body),
   495→        };
   496→      } catch {
   497→        return null;
   498→      }
   499→    }
   500→  }
   501→  return null;
   502→}
