   504→/**
   505→ * Collect contentLocales for all non-default locales that have a variant file.
   506→ */
   507→function attachContentLocales(page: PostData, slug: string): PostData {
   508→  const defaultLocale = siteConfig.i18n.defaultLocale;
   509→  const otherLocales = siteConfig.i18n.locales.filter(l => l !== defaultLocale);
   510→  const contentLocales: NonNullable<PostData['contentLocales']> = {};
   511→  for (const locale of otherLocales) {
   512→    const localeData = loadLocaleContent(slug, locale);
   513→    if (localeData !== null) contentLocales[locale] = localeData;
   514→  }
   515→  return Object.keys(contentLocales).length > 0 ? { ...page, contentLocales } : page;
   516→}
