   648→export function getRelatedPosts(currentSlug: string, limit: number = 3): PostData[] {
   649→  const allPosts = getAllPosts();
   650→  const currentPost = allPosts.find(p => p.slug === currentSlug);
   651→
   652→  if (!currentPost) return [];
   653→
   654→  const related = allPosts
   655→    .filter(post => post.slug !== currentSlug)
   656→    .map(post => {
   657→      let score = 0;
   658→      const commonTags = post.tags.filter(tag => currentPost.tags.includes(tag));
   659→      score += commonTags.length * 2;
   660→
   661→      if (post.category === currentPost.category && post.category !== 'Uncategorized') {
   662→        score += 1;
   663→      }
   664→
   665→      return { post, score };
   666→    })
   667→    .filter(item => item.score > 0)
   668→    .sort((a, b) => b.score - a.score)
   669→    .slice(0, limit)
   670→    .map(item => item.post);
   671→
   672→  return related;
   673→}
