   742→export function getAdjacentPosts(slug: string): { prev: PostData | null; next: PostData | null } {
   743→  const allPosts = getAllPosts(); // sorted desc by date (newest first)
   744→  const index = allPosts.findIndex(p => p.slug === slug);
   745→  if (index === -1) return { prev: null, next: null };
   746→  return {
   747→    prev: index < allPosts.length - 1 ? allPosts[index + 1] : null, // older post
   748→    next: index > 0 ? allPosts[index - 1] : null,                   // newer post
   749→  };

