   866→export function getBookData(slug: string): BookData | null {
   867→  if (!fs.existsSync(booksDirectory)) return null;
   868→  const bookDir = path.join(booksDirectory, slug);
   869→  if (!fs.existsSync(bookDir)) return null;
   870→
   871→  const indexPathMdx = path.join(bookDir, 'index.mdx');
   872→  const indexPathMd = path.join(bookDir, 'index.md');
   873→  let fullPath = '';
   874→  if (fs.existsSync(indexPathMdx)) fullPath = indexPathMdx;
   875→  else if (fs.existsSync(indexPathMd)) fullPath = indexPathMd;
   876→  else return null;
   877→
   878→  const fileContents = fs.readFileSync(fullPath, 'utf8');
   879→  const { data: rawData, content } = matter(fileContents);
   880→
   881→  const parsed = BookSchema.safeParse(rawData);
   882→  if (!parsed.success) {
   883→    console.error(`Invalid book frontmatter in ${fullPath}:`, parsed.error.format());
   884→    return null;
   885→  }
   886→  const data = parsed.data;
   887→
   888→  // Warn about missing chapter files
   889→  const chapters = flattenBookChapters(data.chapters);
   890→  for (const ch of chapters) {
   891→    const chMdx = path.join(bookDir, `${ch.id}.mdx`);
   892→    const chMd = path.join(bookDir, `${ch.id}.md`);
   893→    const chFolderMdx = path.join(bookDir, ch.id, 'index.mdx');
   894→    const chFolderMd = path.join(bookDir, ch.id, 'index.md');
   895→    if (!fs.existsSync(chMdx) && !fs.existsSync(chMd) && !fs.existsSync(chFolderMdx) && !fs.existsSync(chFolderMd)) {
   896→      console.warn(`Book "${slug}": chapter "${ch.id}" not found`);
   897→    }
   898→  }
   899→
   900→  let coverImage = data.coverImage;
   901→  if (coverImage && !coverImage.startsWith('http') && !coverImage.startsWith('/') && !coverImage.startsWith('text:')) {
   902→    const cleanPath = coverImage.replace(/^\.\//, '');
   903→    coverImage = `/books/${slug}/${cleanPath}`;
   904→  }
   905→
   906→  let authors = data.authors;
   907→  if (authors.length === 0) {
   908→    authors = ['Amytis'];
   909→  }
   910→
   911→  return {
   912→    title: data.title,
   913→    slug,
   914→    excerpt: data.excerpt,
   915→    date: data.date,
   916→    coverImage,
   917→    featured: data.featured,
   918→    draft: data.draft,
   919→    authors,
   920→    content: content.trim(),
   921→    toc: data.chapters,
   922→    chapters,
   923→  };
   924→}
