   926→export function getBookChapter(bookSlug: string, chapterSlug: string): BookChapterData | null {
   927→  const book = getBookData(bookSlug);
   928→  if (!book) return null;
   929→
   930→  const bookDir = path.join(booksDirectory, bookSlug);
   931→  const chMdx = path.join(bookDir, `${chapterSlug}.mdx`);
   932→  const chMd = path.join(bookDir, `${chapterSlug}.md`);
   933→  const chFolderMdx = path.join(bookDir, chapterSlug, 'index.mdx');
   934→  const chFolderMd = path.join(bookDir, chapterSlug, 'index.md');
   935→  let fullPath = '';
   936→  let isFolder = false;
   937→  if (fs.existsSync(chMdx)) fullPath = chMdx;
   938→  else if (fs.existsSync(chMd)) fullPath = chMd;
   939→  else if (fs.existsSync(chFolderMdx)) { fullPath = chFolderMdx; isFolder = true; }
   940→  else if (fs.existsSync(chFolderMd)) { fullPath = chFolderMd; isFolder = true; }
   941→  else return null;
   942→
   943→  const fileContents = fs.readFileSync(fullPath, 'utf8');
   944→  const { data: rawData, content } = matter(fileContents);
   945→
   946→  const parsed = BookChapterSchema.safeParse(rawData);
   947→  if (!parsed.success) {
   948→    console.error(`Invalid chapter frontmatter in ${fullPath}:`, parsed.error.format());
   949→    return null;
   950→  }
   951→  const data = parsed.data;
   952→
   953→  if (process.env.NODE_ENV === 'production' && data.draft) {
   954→    return null;
   955→  }
   956→
   957→  const contentWithoutH1 = content.replace(/^\s*#\s+[^\n]+/, '').trim();
   958→  const headings = getHeadings(content);
   959→  const readingTime = calculateReadingTime(contentWithoutH1);
   960→  const excerpt = data.excerpt || generateExcerpt(contentWithoutH1);
   961→
   962→  // Find prev/next
   963→  const chapterIndex = book.chapters.findIndex(ch => ch.id === chapterSlug);
   964→  const prevChapter = chapterIndex > 0 ? book.chapters[chapterIndex - 1] : null;
   965→  const nextChapter = chapterIndex < book.chapters.length - 1 ? book.chapters[chapterIndex + 1] : null;
   966→
   967→  return {
   968→    title: data.title,
   969→    slug: chapterSlug,
   970→    bookSlug,
   971→    content: contentWithoutH1,
   972→    headings,
   973→    excerpt,
   974→    latex: data.latex,
   975→    readingTime,
   976→    isFolder,
   977→    prevChapter: prevChapter ? { title: prevChapter.title, id: prevChapter.id } : null,
   978→    nextChapter: nextChapter ? { title: nextChapter.title, id: nextChapter.id } : null,
   979→  };
   980→}
