   982→export function getAllBooks(): BookData[] {
   983→  if (!fs.existsSync(booksDirectory)) return [];
   984→
   985→  const entries = fs.readdirSync(booksDirectory, { withFileTypes: true });
   986→  const books: BookData[] = [];
   987→
   988→  for (const entry of entries) {
   989→    if (!entry.isDirectory()) continue;
   990→    const book = getBookData(entry.name);
   991→    if (!book) continue;
   992→    if (process.env.NODE_ENV === 'production' && book.draft) continue;
   993→    books.push(book);
   994→  }
   995→
   996→  return books.sort((a, b) => (a.date < b.date ? 1 : -1));
   997→}
