  1117→  // slug format: "YYYY/MM/DD"
  1118→  const parts = slug.split('/');
  1119→  if (parts.length !== 3) return null;
  1120→  const [year, month, day] = parts;
  1121→
  1122→  const basePath = path.join(flowsDirectory, year, month);
  1123→  if (!fs.existsSync(basePath)) return null;
  1124→
  1125→  // Try flat file
  1126→  const mdxPath = path.join(basePath, `${day}.mdx`);
  1127→  const mdPath = path.join(basePath, `${day}.md`);
  1128→  if (fs.existsSync(mdxPath)) return parseFlowFile(mdxPath, slug);
  1129→  if (fs.existsSync(mdPath)) return parseFlowFile(mdPath, slug);
  1130→
  1131→  // Try folder
  1132→  const indexMdx = path.join(basePath, day, 'index.mdx');
  1133→  const indexMd = path.join(basePath, day, 'index.md');
  1134→  if (fs.existsSync(indexMdx)) return parseFlowFile(indexMdx, slug);
