  1154→export function getAdjacentFlows(slug: string): { prev: FlowData | null; next: FlowData | null } {
  1155→  const allFlows = getAllFlows(); // sorted newest-first
  1156→  const index = allFlows.findIndex(f => f.slug === slug);
  1157→  if (index === -1) return { prev: null, next: null };
  1158→
  1159→  return {
  1160→    prev: index < allFlows.length - 1 ? allFlows[index + 1] : null, // older
  1161→    next: index > 0 ? allFlows[index - 1] : null, // newer
  1162→  };
  1163→}
