  1338→    }
  1339→    map.set(n.slug, { url: `/notes/${n.slug}`, type: 'note', title: n.title });
  1340→    n.aliases.forEach(a => {
  1341→      if (map.has(a)) {
  1342→        console.warn(`[slugRegistry] Note alias "${a}" (→ ${n.slug}) conflicts with existing slug; skipping.`);
  1343→      } else {
  1344→        map.set(a, { url: `/notes/${n.slug}`, type: 'note', title: n.title });
  1345→      }
  1346→    });
  1347→  });
  1348→
  1349→  if (fs.existsSync(seriesDirectory)) {
  1350→    fs.readdirSync(seriesDirectory, { withFileTypes: true }).forEach(entry => {
  1351→      if (!entry.isDirectory()) return;
  1352→      const slug = entry.name;
  1353→      const seriesData = getSeriesData(slug);
  1354→      map.set(slug, {
