  1366→// ─── Backlink Index ──────────────────────────────────────────────────────────
  1367→
  1368→export interface BacklinkSource {
  1369→  slug: string;
  1370→  title: string;
  1371→  type: 'post' | 'note' | 'flow' | 'series';
  1372→  url: string;
  1373→  context: string;
  1374→}
  1375→
  1376→function extractWikilinkContext(text: string, matchStart: number, matchEnd: number): string {
  1377→  const RADIUS = 120;
  1378→  const start = Math.max(0, matchStart - RADIUS);
  1379→  const end = Math.min(text.length, matchEnd + RADIUS);
  1380→  let ctx = text.slice(start, end);
  1381→
  1382→  // Replace wikilinks in context with just display text for readability
  1383→  ctx = ctx.replace(/\[\[([^\]|]+?)(?:\|([^\]]+?))?\]\]/g, (_, slug, display) => display || slug);
  1384→
  1385→  if (start > 0) ctx = ctx.replace(/^[^\s.!?]{1,30}/, '').trimStart();
  1386→  if (end < text.length) ctx = ctx.replace(/[^\s.!?]{1,30}$/, '').trimEnd();
  1387→
  1388→  return ctx.trim().slice(0, 200);
  1389→}
  1390→
  1391→function buildBacklinkIndex(): Map<string, BacklinkSource[]> {
  1392→  const index = new Map<string, BacklinkSource[]>();
  1393→
  1394→  const addBacklinks = (
  1395→    content: string,
  1396→    sourceSlug: string,
  1397→    sourceTitle: string,
  1398→    sourceType: BacklinkSource['type'],
  1399→    sourceUrl: string
  1400→  ) => {
  1401→    // Create a fresh RegExp per call to avoid lastIndex issues with 'g' flag
  1402→    const WIKILINK = /\[\[([^\]|]+?)(?:\|([^\]]+?))?\]\]/g;
  1403→    let match;
  1404→    while ((match = WIKILINK.exec(content)) !== null) {
  1405→      const targetSlug = match[1].trim();
  1406→      if (targetSlug === sourceSlug) continue; // skip self-references
  1407→      const context = extractWikilinkContext(content, match.index, match.index + match[0].length);
  1408→      let sources = index.get(targetSlug);
  1409→      if (!sources) {
  1410→        sources = [];
  1411→        index.set(targetSlug, sources);
  1412→      }
  1413→      if (!sources.some(b => b.slug === sourceSlug && b.type === sourceType)) {
  1414→        sources.push({ slug: sourceSlug, title: sourceTitle, type: sourceType, url: sourceUrl, context });
  1415→      }
  1416→    }
  1417→  };
  1418→
  1419→  getAllPosts().forEach(p => addBacklinks(p.content, p.slug, p.title, 'post', getPostUrl(p)));
  1420→  getAllNotes().forEach(n => addBacklinks(n.content, n.slug, n.title, 'note', `/notes/${n.slug}`));
  1421→  getAllFlows().forEach(f => addBacklinks(f.content, f.slug, f.title, 'flow', `/flows/${f.slug}`));
  1422→
  1423→  return index;
  1424→}
  1425→
  1426→let _backlinkIndex: Map<string, BacklinkSource[]> | null = null;
  1427→
  1428→export function getBacklinks(slug: string): BacklinkSource[] {
  1429→  if (!_backlinkIndex || process.env.NODE_ENV !== 'production') _backlinkIndex = buildBacklinkIndex();
  1430→  return _backlinkIndex.get(slug) ?? [];
  1431→}
