## 4. GENERATEMETADATA PATTERN

All pages follow this pattern:

```typescript
export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
  const { slug } = await params;  // Await params Promise
  const data = getDataBySlug(slug);

  if (!data) {
    return { title: 'Not Found' };
  }

  const ogImage = data.coverImage && 
    !data.coverImage.startsWith('text:') && 
    !data.coverImage.startsWith('./')
    ? data.coverImage
    : siteConfig.ogImage;

  return {
    title: `${data.title} | ${resolveLocale(siteConfig.title)}`,
    description: data.excerpt,
    openGraph: {
      title: data.title,
      description: data.excerpt,
      type: 'article' | 'website',
      publishedTime: data.date,  // article type only
      authors: data.authors,     // article type only
      images: [{ url: ogImage, width: 1200, height: 630, alt: data.title }],
      siteName: resolveLocale(siteConfig.title),
    },
    twitter: {
      card: ogImage !== siteConfig.ogImage ? 'summary_large_image' : 'summary',
      title: data.title,
      description: data.excerpt,
      images: [ogImage],
    },
  };
}
```

**Key Points:**
- All `params` are `Promise<T>` in Next.js 15 - must await
- URL decoding: `decodeURIComponent(slug)` for Unicode support
- Fallback to `siteConfig.ogImage` for missing cover images
- External images (http/https, /, text:) are used as-is
- Relative images (./images/...) are resolved to `/posts/{slug}/...` or `/books/{slug}/...`

