#### **Posts** (`/src/app/posts/[slug]/page.tsx:51-91`)
```typescript
export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
  const post = resolvePostFromParam(rawSlug);

  return {
    title: `${post.title} | ${resolveLocale(siteConfig.title)}`,
    description: post.excerpt,
    openGraph: {
      title: post.title,
      description: post.excerpt,
      type: 'article',  // ← Correct OG type!
      publishedTime: post.date,
      authors: post.authors,
      images: [{ url: ogImage, width: 1200, height: 630, alt: post.title }],
      siteName: resolveLocale(siteConfig.title),
    },
    twitter: {
      card: 'summary_large_image',
      title: post.title,
      description: post.excerpt,
      images: [ogImage],
    },
  };
}
```

**Cover Image Logic** (lines 61-63):
- Uses post.coverImage if external URL or absolute path
- Falls back to site's default ogImage if relative path (./images/) or text: placeholder
- Smart fallback prevents broken OG images

#### **Series** (`/src/app/series/[slug]/page.tsx:22-61`)
```typescript
export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
  const seriesData = getSeriesData(slug);

