      url: `${siteConfig.baseUrl}/series/${slug}`,
      siteName: resolveLocale(siteConfig.title),
      images: [{ url: ogImage, width: 1200, height: 630, alt: seriesData.title }],
    },
    twitter: { ... },
  };
}
```

#### **Books (Landing)** (`/src/app/books/[slug]/page.tsx:18-48`)
- Same pattern as series with type: 'website'
- **No publishedTime** (books are evergreen)

#### **Book Chapters** (`/src/app/books/[slug]/[chapter]/page.tsx:31-47`)
```typescript
return {
  title: `${chapter.title} - ${book.title} | ${resolveLocale(siteConfig.title)}`,
  description: chapter.excerpt,
  // ⚠️ Missing: openGraph, twitter!
};
```
**Issue**: Chapters have minimal metadata - no OG graph, no Twitter card

#### **Daily Flows** (`/src/app/flows/[year]/[month]/[day]/page.tsx:24-45`)
```typescript
export async function generateMetadata({ params }: { params: Promise<{ year: string; month: string; day: string }> }): Promise<Metadata> {
  const flow = getFlowBySlug(`${year}/${month}/${day}`);

  return {
    title: `${flow.title} | ${resolveLocale(siteConfig.title)}`,
    description: flow.excerpt,
    openGraph: {
      title: flow.title,
      description: flow.excerpt,
      type: 'article',  // ← Correct type for daily notes
      publishedTime: flow.date,
      url: `${siteConfig.baseUrl}/flows/${year}/${month}/${day}`,
      siteName: resolveLocale(siteConfig.title),
    },
    twitter: { card: 'summary', ... },
  };
}
```

#### **Tags** (`/src/app/tags/[tag]/page.tsx:19-30`)
```typescript
return {
  title: `#${decodedTag} | ${resolveLocale(siteConfig.title)}`,
  description: `${total} posts tagged with "${decodedTag}".`,
  // ⚠️ Missing: openGraph, twitter!
};
```

#### **Authors** (`/src/app/authors/[author]/page.tsx:30-46`)
```typescript
return {
  title: `${resolvedAuthor} | ${resolveLocale(siteConfig.title)}`,
  description: `${posts.length} posts written by ${resolvedAuthor}.`,
  // ⚠️ Missing: openGraph, twitter!
};
```

