  title: string;
  slug: string;
  excerpt?: string;
  date: string;
  coverImage?: string;
  authors: string[];
  chapters: BookChapterEntry[];
}

interface BookChapterData {
  title: string;
  slug: string;
  bookSlug: string;
  excerpt?: string;
}

interface FlowData {
  slug: string;       // "YYYY/MM/DD"
  title: string;
  date: string;
  excerpt: string;
  tags: string[];
}
```

## Site config
- `siteConfig.baseUrl` - absolute base URL
- `siteConfig.title` - site name (may be `{ en: '...', zh: '...' }` — use `resolveLocale()` from `src/lib/i18n.ts`)
