    17→      // frontmatter) would cause notFound() at render time, which in
    18→      // output:export dev mode surfaces as a confusing "missing param" 500.
    19→      if (getBookChapter(book.slug, ch.id) !== null) {
    20→        params.push({ slug: book.slug, chapter: ch.id });
    21→      }
    22→    }
    23→  }
    24→
    25→  // Ensure we never return an empty array with output: export
    26→  return params.length > 0 ? params : [{ slug: '_', chapter: '_' }];
    27→}
