    10→function safeDecodeParam(param: string): string {
    11→  try {
    12→    return decodeURIComponent(param);
    13→  } catch {
    14→    return param;
    15→  }
    16→}
    17→
    18→function resolvePostFromParam(rawSlug: string) {
    19→  const decoded = safeDecodeParam(rawSlug);
    20→  return (
    21→    getPostBySlug(decoded) ||
    22→    getPostBySlug(rawSlug) ||
    23→    getPostBySlug(decoded.normalize('NFC')) ||
    24→    getPostBySlug(decoded.normalize('NFD'))
    25→  );
    26→}
    27→
    28→export async function generateStaticParams() {
    29→  const params: { slug: string; postSlug: string }[] = [];
    30→
    31→  // Custom posts basePath — all posts served at /[basePath]/[slug]
    32→  const basePath = getPostsBasePath();
    33→  if (basePath !== 'posts') {
    34→    getAllPosts().forEach(post => { params.push({ slug: basePath, postSlug: post.slug }); });
    35→  }
    36→
    37→  // Series custom paths — only posts belonging to that series
    38→  for (const [seriesSlug, customPath] of Object.entries(getSeriesCustomPaths())) {
    39→    getSeriesPosts(seriesSlug).forEach(post => { params.push({ slug: customPath, postSlug: post.slug }); });
    40→  }
    41→
    42→  // Placeholder keeps Next.js happy with output: export when no custom paths configured.
    43→  // dynamicParams = false ensures any unrecognised slug/postSlug combo returns 404.
    44→  return params.length > 0 ? params : [{ slug: '_', postSlug: '_' }];
    45→}
    46→
    47→export const dynamicParams = false;
    48→
    49→export async function generateMetadata({
    50→  params,
    51→}: {
    52→  params: Promise<{ slug: string; postSlug: string }>;
    53→}): Promise<Metadata> {
    54→  const { postSlug: rawPostSlug } = await params;
    55→  const post = resolvePostFromParam(rawPostSlug);
    56→
    57→  if (!post) {
    58→    return { title: 'Post Not Found' };
    59→  }
    60→
    61→  const ogImage =
    62→    post.coverImage && !post.coverImage.startsWith('text:') && !post.coverImage.startsWith('./')
    63→      ? post.coverImage
    64→      : siteConfig.ogImage;
    65→
    66→  return {
    67→    title: `${post.title} | ${resolveLocale(siteConfig.title)}`,
    68→    description: post.excerpt,
    69→    openGraph: {
    70→      title: post.title,
    71→      description: post.excerpt,
    72→      type: 'article',
    73→      publishedTime: post.date,
    74→      authors: post.authors,
    75→      images: [
    76→        {
    77→          url: ogImage,
    78→          width: 1200,
    79→          height: 630,
    80→          alt: post.title,
    81→        },
    82→      ],
    83→      siteName: resolveLocale(siteConfig.title),
    84→    },
    85→    twitter: {
    86→      card: 'summary_large_image',
    87→      title: post.title,
    88→      description: post.excerpt,
    89→      images: [ogImage],
    90→    },
    91→  };
    92→}
    93→
    94→export default async function PrefixPostPage({
    95→  params,
    96→}: {
    97→  params: Promise<{ slug: string; postSlug: string }>;
    98→}) {
    99→  const { slug: prefix, postSlug: rawPostSlug } = await params;
   100→
   101→  // Validate the prefix is a known custom path
   102→  const basePath = getPostsBasePath();
   103→  const customPaths = getSeriesCustomPaths();
   104→  const isValidBasePath = prefix === basePath && basePath !== 'posts';
   105→  const matchedSeriesSlug = Object.entries(customPaths).find(([, path]) => path === prefix)?.[0];
   106→
   107→  if (!isValidBasePath && !matchedSeriesSlug) {
   108→    notFound();
   109→  }
   110→
   111→  const post = resolvePostFromParam(rawPostSlug);
   112→  if (!post) {
   113→    notFound();
   114→  }
   115→
   116→  const layout = post.layout || 'post';
   117→
   118→  if (layout === 'simple') {
   119→    return <SimpleLayout post={post} />;
   120→  }
   121→
   122→  const relatedPosts = getRelatedPosts(post.slug);
   123→  const { prev, next } = getAdjacentPosts(post.slug);
   124→  const slugRegistry = buildSlugRegistry();
   125→  const backlinks = getBacklinks(post.slug);
   126→  let seriesPosts: PostData[] = [];
   127→  let seriesTitle: string | undefined;
   128→
   129→  if (post.series) {
   130→    seriesPosts = getSeriesPosts(post.series);
   131→    const seriesData = getSeriesData(post.series);
   132→    seriesTitle = seriesData?.title;
   133→  }
   134→
   135→  return (
   136→    <PostLayout
   137→      post={post}
   138→      relatedPosts={relatedPosts}
   139→      seriesPosts={seriesPosts}
   140→      seriesTitle={seriesTitle}
   141→      prevPost={prev}
   142→      nextPost={next}
   143→      backlinks={backlinks}
   144→      slugRegistry={slugRegistry}
   145→    />
   146→  );
   147→}
