     4→// ── Feature name overrides ────────────────────────────────────────────────
     5→//
     6→// When a user configures e.g. features.series.name.zh = "专栏", these maps
     7→// tell us which translation keys should reflect that name.
     8→
     9→/** Translation keys whose value IS the feature name (simple substitution). */
    10→const FEATURE_SIMPLE_KEYS: Record<string, TranslationKey[]> = {
    11→  series: ['series'],
    12→  books:  ['books', 'book'],
    13→  flow:   ['flow'],
    14→  posts:  ['posts'],
    15→};
    16→
    17→/** Translation keys that CONTAIN the feature name as a substring (compound substitution). */
    18→const FEATURE_COMPOUND_KEYS: Record<string, TranslationKey[]> = {
    19→  series: ['curated_series', 'all_series', 'view_full_series'],
    20→  books:  ['all_books', 'selected_books'],
    21→  flow:   ['all_flows', 'recent_notes'],
    22→  posts:  [],
    23→};
    24→
    25→function substituteInTranslation(original: string, from: string, to: string): string | null {
    26→  if (original.includes(from)) return original.replaceAll(from, to);
    27→  // Case-insensitive fallback for languages like English
    28→  if (original.toLowerCase().includes(from.toLowerCase())) {
