    35→/**
    36→ * Build a map of translation overrides derived from siteConfig.features.*.name.
    37→ * Called once per language; results are cached below.
    38→ */
    39→export function buildFeatureOverrides(lang: string): Partial<Record<TranslationKey, string>> {
    40→  const overrides: Partial<Record<TranslationKey, string>> = {};
    41→  const features = siteConfig.features as Record<string, { name?: Record<string, string> } | undefined>;
    42→  const langT = translations[lang as Language] ?? translations.en;
    43→
    44→  for (const [featureKey, featureConfig] of Object.entries(features)) {
    45→    if (!featureConfig?.name) continue;
    46→    const configuredName = featureConfig.name[lang] ?? featureConfig.name['en'];
    47→    if (!configuredName) continue;
    48→
    49→    const simpleKeys = FEATURE_SIMPLE_KEYS[featureKey] ?? [];
    50→    const defaultName = langT[simpleKeys[0]];
    51→    // Skip if no default mapping or name hasn't changed
    52→    if (!defaultName || configuredName === defaultName) continue;
    53→
    54→    for (const key of simpleKeys) {
    55→      overrides[key] = configuredName;
    56→    }
    57→
    58→    for (const key of (FEATURE_COMPOUND_KEYS[featureKey] ?? [])) {
    59→      const original = langT[key];
    60→      if (!original) continue;
    61→      const substituted = substituteInTranslation(original, defaultName, configuredName);
    62→      if (substituted) overrides[key] = substituted;
    63→    }
    64→  }
    65→
    66→  return overrides;
    67→}
    68→
    69→// Module-level cache — siteConfig is static so overrides never change
    70→const _overridesCache: Record<string, Partial<Record<TranslationKey, string>>> = {};
    71→
    72→function getOverrides(lang: string): Partial<Record<TranslationKey, string>> {
    73→  if (!_overridesCache[lang]) _overridesCache[lang] = buildFeatureOverrides(lang);
    74→  return _overridesCache[lang];
    75→}
