    77→/**
    78→ * Server-side translation helper.
    79→ * For client components, use the `useLanguage()` hook instead.
    80→ */
    81→export const t = (key: TranslationKey): string => {
    82→  const lang = siteConfig.i18n.defaultLocale;
    83→  const overrides = getOverrides(lang);
    84→  if (key in overrides) return overrides[key]!;
    85→  return translations[lang as Language]?.[key] || translations.en[key];
    86→};
    87→
    88→export const tWith = (key: TranslationKey, params: Record<string, string | number>): string => {
    89→  let result = t(key);
    90→  for (const [k, v] of Object.entries(params)) {
    91→    result = result.split(`{${k}}`).join(String(v));
    92→  }
    93→  return result;
    94→};
