```

#### Internal helper

```typescript
function buildPublisher(siteTitle: string, siteUrl: string): SchemaOrganization {
  return { '@type': 'Organization', name: siteTitle, url: siteUrl };
}

function buildAuthors(names: string[]): SchemaPerson[] {
  // Produce at least one Person node. Falls back to site name if names is empty.
  if (names.length === 0) return [];
  return names.map(name => ({ '@type': 'Person', name }));
}

function resolveImageUrl(
  coverImage: string | undefined,
  defaultOgImage: string,
  siteUrl: string
): string {
  // Reject local paths (./images/…) and text placeholders
  if (
    coverImage &&
    !coverImage.startsWith('./') &&
    !coverImage.startsWith('text:') &&
    !coverImage.startsWith('/posts/') // local resolved paths have no SEO value without CDN
  ) {
    // External URL — use as-is
    if (coverImage.startsWith('http')) return coverImage;
  }
  // Fallback: absolute OG image URL
  const base = siteUrl.replace(/\/+$/, '');
  return defaultOgImage.startsWith('http') ? defaultOgImage : `${base}${defaultOgImage}`;
}
```

Note on `resolveImageUrl`: the existing `generateMetadata` functions already use this same logic (`!coverImage.startsWith('text:') && !coverImage.startsWith('./')` → use cover, else use `siteConfig.ogImage`). Our helper mirrors that pattern exactly, but also constructs an absolute URL (schema.org `image` must be absolute).

#### Exact JSON-LD schema structures

