### Full Implementation of `src/lib/json-ld.ts`

```typescript
import { getPostsListUrl } from './urls';

// ── Schema shape types ────────────────────────────────────────────────────────

interface SchemaOrganization {
  '@type': 'Organization';
  name: string;
  url: string;
}

interface SchemaPerson {
  '@type': 'Person';
  name: string;
}

interface SchemaImageObject {
  '@type': 'ImageObject';
  url: string;
}

interface SchemaBlogPosting {
  '@type': 'BlogPosting';
  headline: string;
  description: string | undefined;
  url: string;
  datePublished: string;
  dateModified: string;
  author: SchemaPerson[];
  publisher: SchemaOrganization;
  image: SchemaImageObject;
  keywords: string | undefined;
  mainEntityOfPage: { '@type': 'WebPage'; '@id': string };
}

interface SchemaBook {
  '@type': 'Book';
  name: string;
  description: string | undefined;
  url: string;
  datePublished: string;
  author: SchemaPerson[];
  publisher: SchemaOrganization;
  image: SchemaImageObject | undefined;
}

interface SchemaArticle {
  '@type': 'Article';
  headline: string;
  description: string | undefined;
  url: string;
  datePublished: string;
  author: SchemaPerson[];
  publisher: SchemaOrganization;
  isPartOf: { '@type': 'Book'; '@id': string; name: string };
}

interface SchemaBreadcrumbList {
  '@type': 'BreadcrumbList';
  itemListElement: Array<{
    '@type': 'ListItem';
    position: number;
    name: string;
    item: string;
  }>;
}

type SchemaNode =
  | SchemaBlogPosting
  | SchemaBook
  | SchemaArticle
  | SchemaBreadcrumbList;

interface SchemaGraph {
  '@context': 'https://schema.org';
  '@graph': SchemaNode[];
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function buildPublisher(siteTitle: string, siteUrl: string): SchemaOrganization {
  return { '@type': 'Organization', name: siteTitle, url: siteUrl };
}

function buildAuthors(names: string[]): SchemaPerson[] {
  return names.map(name => ({ '@type': 'Person', name }));
}

/**
 * Resolve an absolute image URL for structured data.
 * Returns undefined when no usable image is available (consumers can omit it).
 * Mirrors the cover-image logic in generateMetadata across all page components.
 */
function resolveAbsoluteImageUrl(
  coverImage: string | undefined,
  defaultOgImage: string,
  siteUrl: string
): string {
  const base = siteUrl.replace(/\/+$/, '');
  const useCover =
    coverImage &&
    !coverImage.startsWith('./') &&
    !coverImage.startsWith('text:') &&
    coverImage.startsWith('http'); // only external URLs are safe for schema.org
  if (useCover) return coverImage!;
  return defaultOgImage.startsWith('http')
    ? defaultOgImage
    : `${base}${defaultOgImage}`;
}

function wrapGraph(nodes: SchemaNode[]): SchemaGraph {
  return { '@context': 'https://schema.org', '@graph': nodes };
}

// ── Public param types ────────────────────────────────────────────────────────

export interface PostJsonLdParams {
  post: {
    title: string;
    excerpt: string;
    date: string;
    authors: string[];
    tags: string[];
    coverImage?: string;
    series?: string;
  };
  postUrl: string;
  seriesTitle?: string;
  seriesUrl?: string;
  siteTitle: string;
  siteUrl: string;
  defaultOgImage: string;
}

export interface BookJsonLdParams {
  book: {
    title: string;
    excerpt?: string;
    date: string;
    authors: string[];
    coverImage?: string;
    slug: string;
  };
  bookUrl: string;
  siteTitle: string;
  siteUrl: string;
  defaultOgImage: string;
}

export interface BookChapterJsonLdParams {
  chapter: {
    title: string;
    excerpt?: string;
    slug: string;
  };
  book: {
    title: string;
    slug: string;
    date: string;
    authors: string[];
  };
  chapterUrl: string;
  bookUrl: string;
  siteTitle: string;
  siteUrl: string;
}

export interface FlowJsonLdParams {
  flow: {
    title: string;
    excerpt: string;
    date: string;
    tags: string[];
  };
  flowUrl: string;
  siteTitle: string;
  siteUrl: string;
  defaultOgImage: string;
}

// ── Builders ──────────────────────────────────────────────────────────────────

export function buildPostJsonLd(params: PostJsonLdParams): SchemaGraph {
  const { post, postUrl, seriesTitle, seriesUrl, siteTitle, siteUrl, defaultOgImage } = params;
  const base = siteUrl.replace(/\/+$/, '');

  const article: SchemaBlogPosting = {
    '@type': 'BlogPosting',
    headline: post.title,
    description: post.excerpt || undefined,
    url: postUrl,
    datePublished: post.date,
    dateModified: post.date,
    author: buildAuthors(post.authors),
    publisher: buildPublisher(siteTitle, base),
    image: {
      '@type': 'ImageObject',
      url: resolveAbsoluteImageUrl(post.coverImage, defaultOgImage, base),
    },
    keywords: post.tags.length > 0 ? post.tags.join(', ') : undefined,
    mainEntityOfPage: { '@type': 'WebPage', '@id': postUrl },
  };

  // Build breadcrumb: Home → [Series or Posts] → Post
  const breadcrumbItems: SchemaBreadcrumbList['itemListElement'] = [
    { '@type': 'ListItem', position: 1, name: 'Home', item: base },
  ];

  if (seriesTitle && seriesUrl) {
    breadcrumbItems.push({
      '@type': 'ListItem',
      position: 2,
      name: seriesTitle,
      item: seriesUrl,
    });
  } else {
    breadcrumbItems.push({
      '@type': 'ListItem',
      position: 2,
      name: 'Posts',
      item: `${base}${getPostsListUrl()}`,
    });
  }

  breadcrumbItems.push({
    '@type': 'ListItem',
    position: breadcrumbItems.length + 1,
    name: post.title,
    item: postUrl,
  });

  const breadcrumb: SchemaBreadcrumbList = {
    '@type': 'BreadcrumbList',
    itemListElement: breadcrumbItems,
  };

  return wrapGraph([article, breadcrumb]);
}

export function buildBookJsonLd(params: BookJsonLdParams): SchemaGraph {
  const { book, bookUrl, siteTitle, siteUrl, defaultOgImage } = params;
  const base = siteUrl.replace(/\/+$/, '');

  const imageUrl = resolveAbsoluteImageUrl(book.coverImage, defaultOgImage, base);

  const bookSchema: SchemaBook = {
    '@type': 'Book',
    name: book.title,
    description: book.excerpt || undefined,
    url: bookUrl,
    datePublished: book.date,
    author: buildAuthors(book.authors),
    publisher: buildPublisher(siteTitle, base),
    image: imageUrl ? { '@type': 'ImageObject', url: imageUrl } : undefined,
  };

  const breadcrumb: SchemaBreadcrumbList = {
    '@type': 'BreadcrumbList',
    itemListElement: [
      { '@type': 'ListItem', position: 1, name: 'Home', item: base },
      { '@type': 'ListItem', position: 2, name: 'Books', item: `${base}/books` },
      { '@type': 'ListItem', position: 3, name: book.title, item: bookUrl },
    ],
  };

  return wrapGraph([bookSchema, breadcrumb]);
}

export function buildBookChapterJsonLd(params: BookChapterJsonLdParams): SchemaGraph {
  const { chapter, book, chapterUrl, bookUrl, siteTitle, siteUrl } = params;
  const base = siteUrl.replace(/\/+$/, '');

  const article: SchemaArticle = {
    '@type': 'Article',
    headline: chapter.title,
    description: chapter.excerpt || undefined,
    url: chapterUrl,
    datePublished: book.date,
    author: buildAuthors(book.authors),
    publisher: buildPublisher(siteTitle, base),
    isPartOf: { '@type': 'Book', '@id': bookUrl, name: book.title },
  };

  const breadcrumb: SchemaBreadcrumbList = {
    '@type': 'BreadcrumbList',
    itemListElement: [
      { '@type': 'ListItem', position: 1, name: 'Home', item: base },
      { '@type': 'ListItem', position: 2, name: 'Books', item: `${base}/books` },
      { '@type': 'ListItem', position: 3, name: book.title, item: bookUrl },
      { '@type': 'ListItem', position: 4, name: chapter.title, item: chapterUrl },
    ],
  };

  return wrapGraph([article, breadcrumb]);
}

export function buildFlowJsonLd(params: FlowJsonLdParams): SchemaGraph {
  const { flow, flowUrl, siteTitle, siteUrl, defaultOgImage } = params;
  const base = siteUrl.replace(/\/+$/, '');

  const article: SchemaBlogPosting = {
    '@type': 'BlogPosting',
    headline: flow.title,
    description: flow.excerpt || undefined,
    url: flowUrl,
    datePublished: flow.date,
    dateModified: flow.date,
    author: [],    // flows have no author field in FlowData
    publisher: buildPublisher(siteTitle, base),
    image: {
      '@type': 'ImageObject',
      url: resolveAbsoluteImageUrl(undefined, defaultOgImage, base),
    },
    keywords: flow.tags.length > 0 ? flow.tags.join(', ') : undefined,
    mainEntityOfPage: { '@type': 'WebPage', '@id': flowUrl },
  };

  return wrapGraph([article]);
}
```

---

### Edge Cases

| Scenario | Handling |
|---|---|
| Post has no authors (`authors: []`) | `buildAuthors([])` returns `[]` — Google still processes the schema, and `siteConfig.posts.authors.default` ensures authors is populated by the data layer before reaching JSON-LD |
| Post has no cover image | `resolveAbsoluteImageUrl` falls back to `defaultOgImage` — always produces a valid URL |
| Post has a local cover image (`/posts/slug/images/cover.jpg`) | Excluded from schema (not externally accessible without CDN); falls back to `defaultOgImage` |
| Post has no excerpt | `post.excerpt` is always populated by `generateExcerpt()` in `markdown.ts`; no null risk |
| Post has no tags | `keywords` field is `undefined` — `JSON.stringify` omits it |
| Post belongs to series but `getSeriesData` returns null | Caller passes `seriesTitle: undefined`; breadcrumb falls back to Posts listing |
| Book has `text:` cover image | `resolveAbsoluteImageUrl` excludes it; book schema `image` will be the OG fallback |
| Book chapter has no excerpt | `description` is `undefined` — omitted by `JSON.stringify` |
| Flow title falls back to date string | Still valid as `headline`; minimal but correct |
| `siteConfig.baseUrl` has trailing slash | `base = siteUrl.replace(/\/+$/, '')` normalizes it everywhere |

---

### Implementation Sequence

1. Create `src/lib/json-ld.ts` with all interfaces, helpers, and builder functions.
2. Modify `src/app/posts/[slug]/page.tsx` — add import, build `jsonLd`, wrap return in fragment with `<script>`.
3. Modify `src/app/[slug]/[postSlug]/page.tsx` — identical changes.
4. Modify `src/app/books/[slug]/page.tsx` — add import, build `jsonLd`, wrap return.
5. Modify `src/app/books/[slug]/[chapter]/page.tsx` — add import, build `jsonLd`, wrap `<BookLayout>` in fragment.
6. Modify `src/app/flows/[year]/[month]/[day]/page.tsx` — add import, build `jsonLd`, wrap return.
7. Validate with Google's Rich Results Test after a `bun run build:dev`.

---

### What Not to Do

- Do not put JSON-LD in layout components (`PostLayout`, `BookLayout`). Layout components cannot know page-specific metadata, and putting structured data there would make it impossible to inject page-specific data without prop-drilling through the entire layout tree.
- Do not add JSON-LD to `src/app/layout.tsx` for a site-level WebSite schema. While valid, a WebSite schema adds little practical value for rich results compared to page-level schemas and is outside the stated requirements.
- Do not use `JSON.stringify(schema, null, 2)` (pretty-printed) in production — compact output reduces HTML payload size.
- Do not add the `@context` field to individual nodes inside `@graph` — it belongs only at the top level.

---

### Critical Files for Implementation

- `/Users/hutusi/workspace/ai/naive/amytis-claude-review/src/lib/json-ld.ts` - New file to create; contains all schema builder logic and TypeScript interfaces
- `/Users/hutusi/workspace/ai/naive/amytis-claude-review/src/app/posts/[slug]/page.tsx` - Primary post page to modify; already resolves `seriesTitle` which is the key data dependency for breadcrumbs
- `/Users/hutusi/workspace/ai/naive/amytis-claude-review/src/app/books/[slug]/[chapter]/page.tsx` - Most complex injection; requires wrapping `<BookLayout>` in a React fragment since the layout component cannot accept `<script>` injection
- `/Users/hutusi/workspace/ai/naive/amytis-claude-review/src/lib/urls.ts` - Supplies `getPostUrl()` and `getPostsListUrl()` used inside the JSON-LD builders for constructing correct breadcrumb URLs
- `/Users/hutusi/workspace/ai/naive/amytis-claude-review/src/app/flows/[year]/[month]/[day]/page.tsx` - Flow page to modify; `flowUrl` is already constructed on line 59 and can be reused directly

