interface SchemaOrganization {
  '@type': 'Organization';
  name: string;
  url: string;
}

interface SchemaPerson {
  '@type': 'Person';
  name: string;
  url?: string;
}

interface SchemaImageObject {
  '@type': 'ImageObject';
  url: string;
}

interface SchemaBlogPosting {
  '@type': 'BlogPosting';
  headline: string;
  description?: string;
  url: string;
  datePublished: string;
  dateModified: string;
  author: SchemaPerson[];
  publisher: SchemaOrganization;
  image: SchemaImageObject;
  keywords?: string;
  mainEntityOfPage: { '@type': 'WebPage'; '@id': string };
}

interface SchemaBook {
  '@type': 'Book';
  name: string;
  description?: string;
  url: string;
  datePublished: string;
  author: SchemaPerson[];
  publisher: SchemaOrganization;
  image?: SchemaImageObject;
}

interface SchemaArticle {
  '@type': 'Article';
  headline: string;
  description?: string;
  url: string;
  datePublished: string;
  author: SchemaPerson[];
  publisher: SchemaOrganization;
  isPartOf: { '@type': 'Book'; '@id': string; name: string };
}

interface SchemaBreadcrumbList {
  '@type': 'BreadcrumbList';
  itemListElement: Array<{
    '@type': 'ListItem';
    position: number;
    name: string;
    item: string;  // absolute URL
  }>;
}

interface SchemaGraph {
  '@context': 'https://schema.org';
  '@graph': Array<
    SchemaBlogPosting | SchemaBook | SchemaArticle | SchemaBreadcrumbList
  >;
}
```

#### Function signatures

```typescript
// Params types — all fields are pre-resolved by the caller

export interface PostJsonLdParams {
  post: {
    title: string;
    excerpt: string;
    date: string;
